import{_ as e,o,c as d,a2 as a}from"./chunks/framework.CGYl2SZ_.js";const c=JSON.parse('{"title":"streaming","description":"streaming 页面","frontmatter":{"title":"streaming","description":"streaming 页面"},"headers":[],"relativePath":"concepts/streaming.md","filePath":"concepts/streaming.md"}');const t=e({name:"concepts/streaming.md"},[["render",function(e,c,t,l,n,s){return o(),d("div",null,[...c[0]||(c[0]=[a('<h1 id="流式传输-分块" tabindex="-1">流式传输 + 分块 <a class="header-anchor" href="#流式传输-分块" aria-label="Permalink to &quot;流式传输 + 分块&quot;">​</a></h1><h1 id="流式传输-分块-1" tabindex="-1">流式传输 + 分块 <a class="header-anchor" href="#流式传输-分块-1" aria-label="Permalink to &quot;流式传输 + 分块&quot;">​</a></h1><p>OpenClaw 有两个独立的流式传输层：</p><ul><li><strong>块流式传输（渠道）：</strong> 在助手编写时发出完成的<strong>块</strong>。这些是正常的渠道消息（不是令牌增量）。</li><li><strong>预览流式传输（Telegram/Discord/Slack）：</strong> 在生成时更新临时<strong>预览消息</strong>。</li></ul><p>目前<strong>没有真正的令牌增量流式传输</strong>到渠道消息。预览流式传输是基于消息的（发送 + 编辑/追加）。</p><h2 id="块流式传输-渠道消息" tabindex="-1">块流式传输（渠道消息） <a class="header-anchor" href="#块流式传输-渠道消息" aria-label="Permalink to &quot;块流式传输（渠道消息）&quot;">​</a></h2><p>块流式传输以粗块形式发送助手输出，因为它变得可用。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Model output</span></span>\n<span class="line"><span>  └─ text_delta/events</span></span>\n<span class="line"><span>       ├─ (blockStreamingBreak=text_end)</span></span>\n<span class="line"><span>       │    └─ chunker emits blocks as buffer grows</span></span>\n<span class="line"><span>       └─ (blockStreamingBreak=message_end)</span></span>\n<span class="line"><span>            └─ chunker flushes at message_end</span></span>\n<span class="line"><span>                   └─ channel send (block replies)</span></span></code></pre></div><p>图例：</p><ul><li><code>text_delta/events</code>：模型流事件（非流式模型可能稀疏）。</li><li><code>chunker</code>：<code>EmbeddedBlockChunker</code> 应用最小/最大边界 + 断点偏好。</li><li><code>channel send</code>：实际出站消息（块回复）。</li></ul><p><strong>控制：</strong></p><ul><li><code>agents.defaults.blockStreamingDefault</code>：<code>&quot;on&quot;</code>/<code>&quot;off&quot;</code>（默认关闭）。</li><li>渠道覆盖：<code>*.blockStreaming</code>（和每账户变体）强制每渠道 <code>&quot;on&quot;</code>/<code>&quot;off&quot;</code>。</li><li><code>agents.defaults.blockStreamingBreak</code>：<code>&quot;text_end&quot;</code> 或 <code>&quot;message_end&quot;</code>。</li><li><code>agents.defaults.blockStreamingChunk</code>：{ <code>minChars</code>, <code>maxChars</code>, <code>breakPreference?</code> }。</li><li><code>agents.defaults.blockStreamingCoalesce</code>：{ <code>minChars?</code>, <code>maxChars?</code>, <code>idleMs?</code> }（在发送前合并流式块）。</li><li>渠道硬上限：<code>*.textChunkLimit</code>（例如 <code>channels.whatsapp.textChunkLimit</code>）。</li><li>渠道分块模式：<code>*.chunkMode</code>（<code>length</code> 默认，<code>newline</code> 在长度分块前在空行（段落边界）处拆分）。</li><li>Discord 软上限：<code>channels.discord.maxLinesPerMessage</code>（默认 17）拆分高回复以避免 UI 剪裁。</li></ul><p><strong>边界语义：</strong></p><ul><li><code>text_end</code>：chunker 发出时立即流式传输块；在每个 <code>text_end</code> 时刷新。</li><li><code>message_end</code>：等待助手消息完成，然后刷新缓冲输出。</li></ul><p><code>message_end</code> 仍使用 chunker 如果缓冲文本超过 <code>maxChars</code>，因此它可以在末尾发出多个块。</p><h2 id="分块算法-低-高边界" tabindex="-1">分块算法（低/高边界） <a class="header-anchor" href="#分块算法-低-高边界" aria-label="Permalink to &quot;分块算法（低/高边界）&quot;">​</a></h2><p>块分块由 <code>EmbeddedBlockChunker</code> 实现：</p><ul><li><strong>低边界：</strong> 直到缓冲区 &gt;= <code>minChars</code> 才发出（除非强制）。</li><li><strong>高边界：</strong> 优先在 <code>maxChars</code> 之前拆分；如强制，则在 <code>maxChars</code> 处拆分。</li><li><strong>断点偏好：</strong> <code>paragraph</code> → <code>newline</code> → <code>sentence</code> → <code>whitespace</code> → 硬断。</li><li><strong>代码围栏：</strong> 永远不在围栏内拆分；如在 <code>maxChars</code> 强制，关闭 + 重新打开围栏以保持 Markdown 有效。</li></ul><p><code>maxChars</code> 被限制为渠道 <code>textChunkLimit</code>，因此您不能超过每渠道上限。</p><h2 id="合并-合并流式传输块" tabindex="-1">合并（合并流式传输块） <a class="header-anchor" href="#合并-合并流式传输块" aria-label="Permalink to &quot;合并（合并流式传输块）&quot;">​</a></h2><p>启用块流式传输时，OpenClaw 可以在发送前<strong>合并连续的块</strong>。这减少了&quot;单行垃圾&quot;同时仍提供渐进输出。</p><ul><li>合并等待<strong>空闲间隙</strong>（<code>idleMs</code>）后再刷新。</li><li>缓冲区以 <code>maxChars</code> 为上限，如果超过则会刷新。</li><li><code>minChars</code> 防止小片段发送直到积累足够文本（最终刷新总是发送剩余文本）。</li><li>连接器来自 <code>blockStreamingChunk.breakPreference</code>（<code>paragraph</code> → <code>\\n\\n</code>，<code>newline</code> → <code>\\n</code>，<code>sentence</code> → space）。</li><li>渠道覆盖可通过 <code>*.blockStreamingCoalesce</code> 获得（包括每账户配置）。</li><li>默认合并 <code>minChars</code> 对于 Signal/Slack/Discord 增加到 1500，除非覆盖。</li></ul><h2 id="块之间的人性化节奏" tabindex="-1">块之间的人性化节奏 <a class="header-anchor" href="#块之间的人性化节奏" aria-label="Permalink to &quot;块之间的人性化节奏&quot;">​</a></h2><p>启用块流式传输时，您可以在块回复之间添加<strong>随机暂停</strong>（第一个块之后）。这使多气泡响应感觉更自然。</p><ul><li>配置：<code>agents.defaults.humanDelay</code>（通过 <code>agents.list[].humanDelay</code> 每代理覆盖）。</li><li>模式：<code>off</code>（默认）、<code>natural</code>（800-2500ms）、<code>custom</code>（<code>minMs</code>/<code>maxMs</code>）。</li><li>仅适用于<strong>块回复</strong>，而不是最终回复或工具摘要。</li></ul><h2 id="流式传输块或全部" tabindex="-1">&quot;流式传输块或全部&quot; <a class="header-anchor" href="#流式传输块或全部" aria-label="Permalink to &quot;&quot;流式传输块或全部&quot;&quot;">​</a></h2><p>这映射到：</p><ul><li><strong>流式传输块：</strong> <code>blockStreamingDefault: &quot;on&quot;</code> + <code>blockStreamingBreak: &quot;text_end&quot;</code>（边走边发出）。非 Telegram 渠道也需要 <code>*.blockStreaming: true</code>。</li><li><strong>最后流式传输全部：</strong> <code>blockStreamingBreak: &quot;message_end&quot;</code>（刷新一次，如果很长可能会多个块）。</li><li><strong>无块流式传输：</strong> <code>blockStreamingDefault: &quot;off&quot;</code>（仅最终回复）。</li></ul><p><strong>渠道注意：</strong> 块流式传输<strong>关闭除非</strong> <code>*.blockStreaming</code> 明确设置为 <code>true</code>。渠道可以在没有块回复的情况下流式传输实时预览（<code>channels.&lt;channel&gt;.streaming</code>）。</p><p>配置位置提醒：<code>blockStreaming*</code> 默认在 <code>agents.defaults</code> 下，而不是根配置。</p><h2 id="预览流式传输模式" tabindex="-1">预览流式传输模式 <a class="header-anchor" href="#预览流式传输模式" aria-label="Permalink to &quot;预览流式传输模式&quot;">​</a></h2><p>规范键：<code>channels.&lt;channel&gt;.streaming</code></p><p>模式：</p><ul><li><code>off</code>：禁用预览流式传输。</li><li><code>partial</code>：被最新文本替换的单个预览。</li><li><code>block</code>：分块/追加步骤的预览更新。</li><li><code>progress</code>：生成期间的进度/状态预览，完成时为最终答案。</li></ul><h3 id="渠道映射" tabindex="-1">渠道映射 <a class="header-anchor" href="#渠道映射" aria-label="Permalink to &quot;渠道映射&quot;">​</a></h3><table tabindex="0"><thead><tr><th>渠道</th><th><code>off</code></th><th><code>partial</code></th><th><code>block</code></th><th><code>progress</code></th></tr></thead><tbody><tr><td>Telegram</td><td>✅</td><td>✅</td><td>✅</td><td>映射到 <code>partial</code></td></tr><tr><td>Discord</td><td>✅</td><td>✅</td><td>✅</td><td>映射到 <code>partial</code></td></tr><tr><td>Slack</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><p>仅 Slack：</p><ul><li><code>channels.slack.nativeStreaming</code> 在 <code>streaming=partial</code> 时切换 Slack 本地流式传输 API 调用（默认：<code>true</code>）。</li></ul><p>旧键迁移：</p><ul><li>Telegram：<code>streamMode</code> + 布尔 <code>streaming</code> 自动迁移到 <code>streaming</code> 枚举。</li><li>Discord：<code>streamMode</code> + 布尔 <code>streaming</code> 自动迁移到 <code>streaming</code> 枚举。</li><li>Slack：<code>streamMode</code> 自动迁移到 <code>streaming</code> 枚举；布尔 <code>streaming</code> 自动迁移到 <code>nativeStreaming</code>。</li></ul><h3 id="运行时行为" tabindex="-1">运行时行为 <a class="header-anchor" href="#运行时行为" aria-label="Permalink to &quot;运行时行为&quot;">​</a></h3><p>Telegram：</p><ul><li>使用 <code>sendMessage</code> + <code>editMessageText</code> 预览更新，跨 DM 和群组/主题。</li><li>当明确启用 Telegram 块流式传输时跳过预览流式传输（避免双重流式传输）。</li><li><code>/reasoning stream</code> 可以将推理写入预览。</li></ul><p>Discord：</p><ul><li>使用发送 + 编辑预览消息。</li><li><code>block</code> 模式使用草稿分块（<code>draftChunk</code>）。</li><li>当明确启用 Discord 块流式传输时跳过预览流式传输。</li></ul><p>Slack：</p><ul><li><code>partial</code> 可以在可用时使用 Slack 本地流式传输（<code>chat.startStream</code>/<code>append</code>/<code>stop</code>）。</li><li><code>block</code> 使用追加样式草稿预览。</li><li><code>progress</code> 使用状态预览文本，然后是最终答案。</li></ul>',47)])])}]]);export{c as __pageData,t as default};
